// Internal helper for data-view-regression-check.mjs.
//
// Reads a JSON array of fixture filenames from stdin, builds the SQL each
// fixture's request resolves to via get_data_view_results_query, and emits
// {[filename]: {sql, error}} as JSON on stdout. Intended to be spawned in a
// git worktree so the caller can compare SQL generated by arbitrary refs.

import { get_data_view_results_query, load_data_view_test_queries_sync } from '#libs-server'

const read_stdin = () =>
  new Promise((resolve) => {
    let buf = ''
    process.stdin.setEncoding('utf8')
    process.stdin.on('data', (c) => (buf += c))
    process.stdin.on('end', () => resolve(buf))
  })

const main = async () => {
  const raw = await read_stdin()
  const filenames = JSON.parse(raw.trim() || '[]')
  const want = new Set(filenames)
  const fixtures = load_data_view_test_queries_sync().filter((f) =>
    want.size === 0 ? true : want.has(f.filename)
  )

  const out = {}
  for (const fixture of fixtures) {
    try {
      const { query } = await get_data_view_results_query(fixture.request)
      out[fixture.filename] = { sql: query.toString(), error: null }
    } catch (e) {
      out[fixture.filename] = { sql: null, error: e && e.message ? e.message : String(e) }
    }
  }
  process.stdout.write(JSON.stringify(out))
}

main().catch((e) => {
  process.stderr.write(`fatal: ${e && e.stack ? e.stack : e}\n`)
  process.exit(1)
})
